package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.quote.*;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.domain.quote.QuoteLine;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import jakarta.validation.constraints.*;import org.springframework.security.core.Authentication;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.math.*;import java.time.*;import java.util.*;
@RestController @RequestMapping("/api/supplier/v1/quotes")public class SupplierQuoteController{private final SupplierQuoteApplicationService service;private final CommandContextFactory contexts;public SupplierQuoteController(SupplierQuoteApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping public ApiResponse<PageResult<SupplierQuoteView>> page(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(required=false)String keyword,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.page(supplierId,scope(jwt),status,keyword,pageNo,pageSize),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@GetMapping("/{id}")public ApiResponse<SupplierQuoteView> detail(@PathVariable long id,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ApiResponse.success(service.detail(id,scope(jwt)),request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}@PostMapping public ApiResponse<CommandResult> create(@Valid @RequestBody Create body,HttpServletRequest request,Authentication authentication){return ok(service.create(body.supplierId(),body.rfqId(),body.rfqNo(),body.currency(),body.validFrom(),body.validTo(),toLines(body.lines()),contexts.create(request,authentication)),request);}@PutMapping("/{id}")public ApiResponse<CommandResult> modifyDraft(@PathVariable long id,@Valid @RequestBody Modify body,HttpServletRequest request,Authentication authentication){return ok(service.modifyDraft(id,body.version(),body.validFrom(),body.validTo(),toLines(body.lines()),contexts.create(request,authentication)),request);}@PostMapping("/{id}/submit")public ApiResponse<CommandResult> submit(@PathVariable long id,@Valid @RequestBody Version body,HttpServletRequest request,Authentication authentication){return ok(service.submit(id,body.version(),contexts.create(request,authentication)),request);}@PostMapping("/{id}/confirm")public ApiResponse<CommandResult> confirm(@PathVariable long id,@Valid @RequestBody Version body,HttpServletRequest request,Authentication authentication){return ok(service.confirm(id,body.version(),contexts.create(request,authentication)),request);}@PostMapping("/{id}/adopt")public ApiResponse<CommandResult> adopt(@PathVariable long id,@Valid @RequestBody Adopt body,HttpServletRequest request,Authentication authentication){return ok(service.adopt(id,body.version(),body.priceAgreementRef(),contexts.create(request,authentication)),request);}@PostMapping("/{id}/reject")public ApiResponse<CommandResult> reject(@PathVariable long id,@Valid @RequestBody Reject body,HttpServletRequest request,Authentication authentication){return ok(service.reject(id,body.version(),body.reason(),contexts.create(request,authentication)),request);}private List<QuoteLine> toLines(List<Line> lines){return lines.stream().map(line->new QuoteLine(line.lineId()==null?0:line.lineId(),line.skuCode(),line.quoteQty(),line.unitPrice(),line.taxRate(),line.deliveryDays(),line.moq())).toList();}private ApiResponse<CommandResult> ok(CommandResult value,HttpServletRequest request){return ApiResponse.success(value,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number value=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return value==null?null:value.longValue();}public record Create(@Positive long supplierId,Long rfqId,String rfqNo,@NotBlank String currency,@NotNull LocalDate validFrom,@NotNull LocalDate validTo,@NotEmpty List<Line> lines){}public record Modify(@PositiveOrZero int version,@NotNull LocalDate validFrom,@NotNull LocalDate validTo,@NotEmpty List<Line> lines){}public record Line(Long lineId,@NotBlank String skuCode,@NotNull @DecimalMin("0.0001")BigDecimal quoteQty,@NotNull @DecimalMin("0.000001")BigDecimal unitPrice,@NotNull @DecimalMin("0")@DecimalMax("100")BigDecimal taxRate,@PositiveOrZero int deliveryDays,@NotNull @DecimalMin("0.0001")BigDecimal moq){}public record Version(@PositiveOrZero int version){}public record Adopt(@PositiveOrZero int version,@NotBlank String priceAgreementRef){}public record Reject(@PositiveOrZero int version,@NotBlank String reason){} }
